/* Helper: search all DataElements -> Rows -> Edits for an edit by name. Returns the edit.Value as String or the provided default (String or null). */ fun findEdit(editName, defaultVal) = (payload.Transactions[0].DataElements flatMap ((de) -> de.Rows flatMap ((r) -> r.Edits)) filter ((e) -> e.Name == editName) map ((e) -> e.Value))[0] default defaultVal
