 "N"), Class1id: findEdit("class1id", null), Class2id: findEdit("class2id", null), Class3id: findEdit("class3id", null), Class4id: findEdit("class4id", null), Class5id: findEdit("class5id", null), RMA: findEdit("rma", "N"), FreightCd: findEdit("freight_cd", null), BillingDescription: findEdit("billing_description", "Bill Recipient"), CaptureUsage: findEdit("capture_usage", "true"), JobNo: findEdit("job_no", null), InvoiceBatchNumber: findEdit("invoice_batch_number", null), InvoiceExchangeRateSource: findEdit("invoice_exchange_rate_source", "Invoice"), ShipToPhone: findEdit("ship_to_phone", null), ApplyBuilderAllowanceFlag: findEdit("apply_builder_allowance_flag", "N"), QuoteExpirationDate @(xsi#nil: "true"): null, PromiseDate: findEdit("promise_date", "2026-05-15T00:00:00"), CreateInvoice: findEdit("create_invoice", "false"), CStrategicPriceLibraryId: findEdit("cstrategicpricelibraryid", null), MerchandiseCreditFlag: findEdit("merchandise_credit_flag", "N"), OrderPriorityId: findEdit("order_priority_id", null), UpsCode: findEdit("ups_code", null), PlacedByName: findEdit("placed_by_name", null), RequiredPaymentUponRelease: findEdit("required_payment_upon_release", "N"), FreightOut: findEdit("freight_out", "0"), PickTicketType: findEdit("pick_ticket_type", "UT"), ThirdPartyBilling: findEdit("third_party_billing", "B"), UserDefinedFields: null, CurrencyID: findEdit("currency_id", "1"), Completed: findEdit("completed", "N"), Quote: findEdit("quote", "N"), DeletedFlag: findEdit("deleted_flag", "N"), CancelledFlag: findEdit("cancelled_flag", "N"), InvoiceNo: findEdit("invoice_no", null), QuoteType @(xsi#nil: "true"): null, WebReferenceNo: findEdit("web_reference_no", null) }

